3_real_world_example.code:
// Viewing a profile (GET is the default, no body needed)
fetch('/api/users/123');

// Creating a new user (POST requires a body payload)
fetch('/api/users', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ name: 'Alice', age: 25 })
});

// Deleting a user (DELETE)
fetch('/api/users/123', { method: 'DELETE' });

